    POLAR_SING_LOC_LAT: Double = 0.0,
    POLAR_SING_LOC_LON: Double = 0.0,
    EMG_IND: Bool = false,
    DROP_PT_IND: Bool = false,
    LAUNCH_TIMEOffset LAUNCH_TIME: Offset = Offset(),
